import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";
import "./App.css";

function App() {
  const [permissionAsked, setPermissionAsked] = useState(false);
  const [cameraActive, setCameraActive] = useState(false);
  const [scannedSong, setScannedSong] = useState(null);   // tylko zeskanowana nazwa
  const [currentSong, setCurrentSong] = useState(null);   // aktualnie odtwarzana
  const [audioObj, setAudioObj] = useState(null);

  // 1. Uruchom skaner (wymagany gest na iOS)
  const startScanner = () => {
    setCameraActive(true);
    setPermissionAsked(true);
  };

  // 2. Po zeskanowaniu – tylko zapisujemy nazwę
  const handleScan = (results) => {
    if (results?.length > 0) {
      const songName = results[0]?.rawValue?.trim();
      if (songName && songName !== scannedSong) {
        setScannedSong(songName);
        setCameraActive(false); // chowamy skaner
      }
    }
  };

  // 3. Odtwarzanie – dopiero po TAPNIĘCIU użytkownika → iOS pozwala!
  const playSong = () => {
    if (audioObj) {
      audioObj.pause();
      audioObj.currentTime = 0;
    }

    const audio = new Audio(`/audio/${scannedSong}.mp3`);

    audio.play()
      .then(() => {
        setCurrentSong(scannedSong);
        setScannedSong(null); // czyścimy, żeby nie pokazywał się znowu przycisk
      })
      .catch(err => {
        alert("Błąd odtwarzania: " + err.message);
        console.error(err);
      });

    setAudioObj(audio);
  };

  // 4. Stop i powrót do skanera
  const stopAndReturn = () => {
    if (audioObj) {
      audioObj.pause();
      audioObj.currentTime = 0;
      setAudioObj(null);
    }
    setCurrentSong(null);
    setScannedSong(null);
    setCameraActive(true);
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>QR → Muzyka</h1>

        {/* Ekran startowy */}
        {!permissionAsked && (
          <div className="start-screen">
            <p>Naciśnij przycisk, aby rozpocząć</p>
            <button className="big-start-btn" onClick={startScanner}>
              Uruchom skaner
            </button>
          </div>
        )}

        {/* Tryb skanowania */}
        {permissionAsked && !currentSong && !scannedSong && cameraActive && (
          <>
            <div className="scanner-box">
              <Scanner onScan={handleScan} />
            </div>
            <p>Nakieruj na kod QR z nazwą piosenki</p>
          </>
        )}

        {/* Po zeskanowaniu – przycisk ODTWÓRZ (wymagany gest!) */}
        {scannedSong && (
          <div className="ready-to-play">
            <h2>Znaleziono:</h2>
            <h3>{scannedSong}</h3>
            <button className="play-btn" onClick={playSong}>
              Odtwórz piosenkę
            </button>
            <button className="cancel-btn" onClick={() => { setScannedSong(null); setCameraActive(true); }}>
              Anuluj
            </button>
          </div>
        )}

        {/* Tryb odtwarzania */}
        {currentSong && (
          <div className="player-screen">
            <h2>Teraz gra:</h2>
            <h3>{currentSong}</h3>
            <button className="stop-btn" onClick={stopAndReturn}>
              Stop i wróć do skanera
            </button>
          </div>
        )}
      </header>
    </div>
  );
}

export default App;
